# Description

When a search result is clicked, every case-insensitive substring match for
the search term inside the opened note is painted yellow for 10 seconds and
then quietly cleared. Uses the CSS Custom Highlight API
(`::highlight(search-hit)`), so it overlays text without touching the DOM and
cannot disturb `$CodeSyntaxHighlightPlugin`'s syntax-highlighting spans.

The term arrives via the `search.result.clicked` event published by
`core.search`. Only terms whose trimmed length is at least 3 characters are
highlighted, mirroring typical incremental-search ergonomics.

# Meta

<<pluginMeta SearchHighlight>>

# Code

```javascript
(function () {
  const meta = {
    name: 'SearchHighlight',
    version: '0.1.0',
    platform: '0.26.0',
    description:
      'Paint search-term matches in the opened note for 10s via CSS Custom Highlight API.',
  };

  const NAME = 'search-hit';
  const MIN = 3;
  const TTL = 10_000;

  let pending = null; // {title, term} captured by search.result.clicked
  let clearTimer = null; // setTimeout id for the active highlight

  function onSearchResultClicked({title, term}) {
    if (!title || typeof term !== 'string') return;
    const t = term.trim();
    pending = t.length >= MIN ? {title, term: t} : null;
  }

  // The clicked note can arrive via either path: a fresh render (`tiddler.rendered`,
  // payload `{tiddler, newElement}`) when it wasn't on the story, or a refocus
  // (`tiddler.refocus`, payload `title`) when it was already open. Both must
  // trigger the highlight or the in-place case silently does nothing.
  function applyPendingHighlight(title, root) {
    if (!pending || pending.title !== title || !root) return;
    const term = pending.term;
    pending = null;

    const ranges = findRanges(root, term);
    if (!ranges.length) return;

    if (clearTimer) {
      window.clearTimeout(clearTimer);
      clearTimer = null;
    }
    CSS.highlights.set(NAME, new Highlight(...ranges));
    clearTimer = window.setTimeout(() => {
      CSS.highlights.delete(NAME);
      clearTimer = null;
    }, TTL);
  }

  function onTiddlerRenderedForHighlight({tiddler, newElement}) {
    applyPendingHighlight(tiddler?.title, newElement?.querySelector('.text'));
  }

  function onTiddlerRefocusForHighlight(title) {
    applyPendingHighlight(title, tw.run.getTiddlerElement(title)?.querySelector('.text'));
  }

  function findRanges(root, term) {
    const needle = term.toLowerCase();
    const ranges = [];
    const walker = document.createTreeWalker(root, NodeFilter.SHOW_TEXT);
    for (let node; (node = walker.nextNode()); ) {
      const hay = node.nodeValue.toLowerCase();
      let i = 0;
      while ((i = hay.indexOf(needle, i)) !== -1) {
        const r = document.createRange();
        r.setStart(node, i);
        r.setEnd(node, i + needle.length);
        ranges.push(r);
        i += needle.length;
      }
    }
    return ranges;
  }

  function installSheet() {
    const sheet = new CSSStyleSheet();
    sheet.replaceSync(`
      ::highlight(search-hit) {
        background-color: var(--search-hit-bg, #bc9b5c);
        color: inherit;
        animation: search-hit-fade 10s linear forwards;
      }
      @keyframes search-hit-fade {
        0%, 90% { background-color: var(--search-hit-bg, #fff59d); }
        100%    { background-color: transparent; }
      }
    `);
    document.adoptedStyleSheets = [...document.adoptedStyleSheets, sheet];
  }

  return {
    meta,
    init() {
      if (typeof Highlight === 'undefined' || !CSS?.highlights) return; // older browser → no-op
      installSheet();
      tw.events.subscribe('search.result.clicked', onSearchResultClicked);
      tw.events.subscribe('tiddler.rendered', onTiddlerRenderedForHighlight);
      tw.events.subscribe('tiddler.refocus', onTiddlerRefocusForHighlight);
    },
  };
})();
```

# Description

Renders tiddlers of `type: script/js` as a small literate page: the leading
`/** ... */` JSDoc-style block is extracted, its leading `*` markers
stripped, and the body rendered as markdown; the rest of the script is
wrapped in a ` ```javascript ` fenced code block. Both halves are routed
back through the `markdown.render` event, so whichever markdown engine the
user has installed renders both prose and code.

This plugin doubles as a demo of two ideas at once: hooking
`renderer.override` to claim a built-in tiddler type, and composing
pipelines (renderer → markdown). With no JSDoc header the whole script
renders as a single fenced code block.

See [[ExampleScript]] for a live demo.

# Meta

<<pluginMeta CodeRenderer>>

# Code

```javascript
// tags: $Plugin
(function () {
  // This makes pure .js plugins and scripts more readable in twikki
  // by extracting the description (/** ... */ block) off the source
  function splitJsDoc(text) {
    const m = /^\s*\/\*\*([\s\S]*?)\*\//.exec(text);
    if (!m) return {comment: '', code: text};
    const comment = m[1]
      .split('\n')
      .map(l => l.replace(/^\s*\*\s?/, ''))
      .join('\n')
      .trim();
    return {comment, code: text.slice(m[0].length).replace(/^\n+/, '')};
  }
  return {
    meta: {
      name: 'CodeRenderer',
      version: '0.0.1',
      platform: '0.26.0',
      author: 'TWikki',
      description:
        'Renders type=script/js tiddlers by lifting the leading /** ... */ JSDoc block as markdown and wrapping the rest in a ```javascript fence, then routing both halves back through markdown.render. See [[ExampleScript]] for a live demo.',
    },
    start() {
      const esc = tw.core.common.escapeHtml;
      tw.events.subscribe('renderer.override', function codeRenderer({tiddler, text}) {
        if (tiddler.type !== 'script/js') return null;
        const {comment, code} = splitJsDoc(text);
        const md = (comment ? comment + '\n\n' : '') + '```javascript\n' + code + '\n```';
        // Route back through markdown.render so any plugin-supplied engine
        // wins. Same fallback shape as renderMarkdown() in core.render: if
        // no handler is subscribed (e.g. ?safemode), drop to an escaped
        // <pre> of the composed markdown.
        const results = tw.events.send('markdown.render', md);
        const html = results?.[0] ?? `<pre><code>${esc(md)}</code></pre>`;
        return `<div class="code-rendered">${html}</div>`;
      });
    },
  };
})();
```

